namespace Bikeapelago.Api.Tests.Integration;

/// <summary>
/// Validates that nodes generated by PostGIS are snappable to the correct road network
/// by auditing each coordinate against GraphHopper's /nearest endpoint.
///
/// A large snap delta (50m+) means PostGIS returned a node on an invalid road type
/// (e.g. motorway, footway) for the requested mode, and GraphHopper had to seek
/// the nearest valid road elsewhere.
///
/// Requires live Docker stack. Set env vars to override defaults:
///   BIKEAPELAGO_API_URL  (default: http://bikeapelago-api.orb.local)
///   BIKEAPELAGO_TOKEN
///   GRAPHHOPPER_URL      (default: http://localhost:8990)
/// </summary>
[Trait("Category", "Integration")]
public class GraphHopperNodeValidationTests : IAsyncLifetime
{
    private static readonly string ApiBase =
        Environment.GetEnvironmentVariable("BIKEAPELAGO_API_URL")
        ?? "http://bikeapelago-api.orb.local";

    private static readonly string GraphHopperBase =
        Environment.GetEnvironmentVariable("GRAPHHOPPER_URL")
        ?? "http://localhost:8990";

    private static readonly string Token =
        Environment.GetEnvironmentVariable("BIKEAPELAGO_TOKEN")
