    public GraphHopperNodeValidationTests()
    {
        _apiClient = new HttpClient { BaseAddress = new Uri(ApiBase) };
        _apiClient.DefaultRequestHeaders.Authorization =
            new AuthenticationHeaderValue("Bearer", Token);
        _apiClient.Timeout = TimeSpan.FromMinutes(5);

        _ghClient = new HttpClient { BaseAddress = new Uri(GraphHopperBase) };
        _ghClient.Timeout = TimeSpan.FromSeconds(15);
    }

    public Task InitializeAsync() => Task.CompletedTask;

    public async Task DisposeAsync()
    {
        foreach (var id in _createdSessionIds)
        {
            try { await _apiClient.DeleteAsync($"/api/sessions/{id}"); }
            catch { /* best-effort */ }
        }
        _apiClient.Dispose();
        _ghClient.Dispose();
    }

