    // ── Core audit logic ──────────────────────────────────────────────────

    private async Task<List<SnapResult>> AuditWithGraphHopper(
        List<NodeDto> nodes, string vehicle)
    {
        using var semaphore = new SemaphoreSlim(20, 20);

        var tasks = nodes.Select(async node =>
        {
            await semaphore.WaitAsync();
            try
            {
                var url = $"/nearest?point={node.Lat},{node.Lon}&vehicle={vehicle}&type=json";
                var resp = await _ghClient.GetAsync(url);

                if (!resp.IsSuccessStatusCode)
                    return new SnapResult(node, SnapMeters: double.MaxValue, Error: $"GH returned {(int)resp.StatusCode}");

                var body = await resp.Content.ReadAsStringAsync();
                using var doc = JsonDocument.Parse(body);
                var coords = doc.RootElement.GetProperty("coordinates");
                double snappedLon = coords[0].GetDouble();
                double snappedLat = coords[1].GetDouble();
                double snapMeters = HaversineMeters(node.Lat, node.Lon, snappedLat, snappedLon);

                return new SnapResult(node, snapMeters, Error: null);
            }
            catch (Exception ex)
            {
                return new SnapResult(node, SnapMeters: double.MaxValue, Error: ex.Message);
            }
            finally
            {
                semaphore.Release();
            }
        });

        return (await Task.WhenAll(tasks)).ToList();
    }

    private static void AssertSnapResults(List<SnapResult> results, string label)
    {
        var errors    = results.Where(r => r.Error != null).ToList();
        var hardFails = results.Where(r => r.Error == null && r.SnapMeters >= HardFailMeters).ToList();
        var softFails = results.Where(r => r.Error == null && r.SnapMeters >= MaxSnapMeters && r.SnapMeters < HardFailMeters).ToList();
        var passed    = results.Count(r => r.Error == null && r.SnapMeters < MaxSnapMeters);
        var validSnaps = results.Where(r => r.Error == null).ToList();

        foreach (var f in hardFails)
            Console.WriteLine($"[HARD FAIL {label}] ({f.Node.Lat:F5},{f.Node.Lon:F5}) snapped {f.SnapMeters:F1}m — likely wrong road type");
        foreach (var f in softFails)
            Console.WriteLine($"[SOFT FAIL {label}] ({f.Node.Lat:F5},{f.Node.Lon:F5}) snapped {f.SnapMeters:F1}m");
        foreach (var e in errors)
            Console.WriteLine($"[ERROR {label}] ({e.Node.Lat:F5},{e.Node.Lon:F5}) {e.Error}");

        double passRate = (double)passed / results.Count * 100;
        double avgSnap  = validSnaps.Count > 0 ? validSnaps.Average(r => r.SnapMeters) : 0;
        double maxSnap  = validSnaps.Count > 0 ? validSnaps.Max(r => r.SnapMeters) : 0;
        Console.WriteLine($"[{label}] {passed}/{results.Count} passed ({passRate:F1}%)  " +
                          $"soft={softFails.Count}  hard={hardFails.Count}  errors={errors.Count}  " +
                          $"avg={avgSnap:F1}m  max={maxSnap:F1}m");

        Assert.True(hardFails.Count == 0,
            $"{hardFails.Count} nodes for [{label}] snapped {HardFailMeters}m+: " +
            string.Join(", ", hardFails.Take(5).Select(f => $"({f.Node.Lat:F5},{f.Node.Lon:F5})={f.SnapMeters:F0}m")));

        Assert.True(errors.Count == 0,
            $"{errors.Count} GraphHopper calls failed for [{label}]: " +
            string.Join("; ", errors.Take(3).Select(e => e.Error)));

        Assert.True(softFails.Count == 0,
            $"{softFails.Count} nodes for [{label}] snapped between {MaxSnapMeters}–{HardFailMeters}m");
    }

    // ── Helpers ───────────────────────────────────────────────────────────

    private async Task<List<NodeDto>> GenerateNodes(
        City city, string mode, int nodeCount, double radiusMeters)
    {
        var createResp = await _apiClient.PostAsJsonAsync("/api/sessions", new
        {
            center_lat = city.Lat,
            center_lon = city.Lon,
            name = $"gh-audit-{mode}-{nodeCount}-{city.Name.Replace(", ", "-").Replace(" ", "")}",
            radius = (int)radiusMeters,
            status = "SetupInProgress",
            user = UserId
        });
        createResp.EnsureSuccessStatusCode();
        var session = await createResp.Content.ReadFromJsonAsync<SessionDto>()
            ?? throw new InvalidOperationException("Null session");
        _createdSessionIds.Add(session.Id);

        var genResp = await _apiClient.PostAsJsonAsync($"/api/sessions/{session.Id}/generate", new
        {
            centerLat = city.Lat,
            centerLon = city.Lon,
            radius = radiusMeters,
            nodeCount,
            mode
        });
        Assert.True(genResp.IsSuccessStatusCode,
            $"Generate failed [{city.Name}/{mode}]: {await genResp.Content.ReadAsStringAsync()}");

        var nodes = await _apiClient
            .GetFromJsonAsync<List<NodeDto>>($"/api/sessions/{session.Id}/nodes")
            ?? throw new InvalidOperationException("Null nodes");

        Assert.Equal(nodeCount, nodes.Count);
        return nodes;
    }

    private static double HaversineMeters(double lat1, double lon1, double lat2, double lon2)
    {
        const double R = 6_371_000;
        double dLat = (lat2 - lat1) * Math.PI / 180;
        double dLon = (lon2 - lon1) * Math.PI / 180;
        double a = Math.Sin(dLat / 2) * Math.Sin(dLat / 2)
                 + Math.Cos(lat1 * Math.PI / 180) * Math.Cos(lat2 * Math.PI / 180)
                 * Math.Sin(dLon / 2) * Math.Sin(dLon / 2);
        return R * 2 * Math.Atan2(Math.Sqrt(a), Math.Sqrt(1 - a));
    }

    private record SnapResult(NodeDto Node, double SnapMeters, string? Error);
    private record SessionDto([property: JsonPropertyName("id")] Guid Id);
    private record NodeDto(
        [property: JsonPropertyName("lat")] double Lat,
        [property: JsonPropertyName("lon")] double Lon);
}
